import { exec } from 'node:child_process'
import { promisify } from 'node:util'
import {
  AYNITE_SUBDIRS,
  exists,
  getAyniteDir,
  joinPaths,
  readdir,
} from '../../lib/path'

const execAsync = promisify(exec)

export async function getSystemFonts(): Promise<string[]> {
  try {
    const { stdout } = await execAsync(
      'fc-list :lang=en --format="%{family}\n"',
    )
    return [
      ...new Set(
        stdout
          .split('\n')
          .map((f) => f.trim())
          .filter(Boolean),
      ),
    ].sort()
  } catch {
    return [
      'Inter',
      'Arial',
      'Helvetica',
      'Times New Roman',
      'Courier New',
      'Georgia',
      'Verdana',
    ]
  }
}

export async function getAvailableViews(): Promise<
  { id: string; name: string }[]
> {
  const viewsDir = joinPaths(getAyniteDir(), AYNITE_SUBDIRS.VIEWS)
  if (!(await exists(viewsDir))) return []

  const entries = await readdir(viewsDir)
  const views: { id: string; name: string }[] = []

  for (const entry of entries) {
    if (entry.isDirectory()) {
      const indexPath = joinPaths(viewsDir, entry.name, 'index.html')
      if (await exists(indexPath)) {
        // Simple name transformation: aichat -> AI Chat
        const name = entry.name
          .split('-')
          .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
          .join(' ')
          .replace('Aichat', 'AI Chat')
          .replace('Treeview', 'File Explorer')

        views.push({
          id: entry.name,
          name,
        })
      }
    }
  }
  return views
}

import { getCommandPath, getCommandsDir } from '../../lib/path'
import {
  getSpellConfig,
  listAvailableSpells,
  restoreSpell as restoreBundledSpell,
  restoreDefaultSpells,
  saveSpellConfig,
} from './spell-installer'

export async function getCommandsConfig() {
  return getSpellConfig('commands', getCommandsDir())
}

export async function saveCommandsConfig(config: any) {
  return saveSpellConfig('commands', config)
}

export async function listAvailableCommands() {
  return listAvailableSpells('commands', getCommandsDir(), 'COMMAND.md', true)
}

export async function restoreDefaultCommands() {
  const defaultDir = getCommandsDir()
  await saveCommandsConfig({ folders: [defaultDir] })
  return restoreDefaultSpells('commands', ['hello-command'], (name) =>
    getCommandPath(name),
  )
}

export async function restoreCommand(commandName: string) {
  return restoreBundledSpell(
    'commands',
    commandName,
    getCommandPath(commandName),
  )
}

import { exec } from 'node:child_process'
import { promisify } from 'node:util'
import { jsonSchema } from '@ai-sdk/provider-utils'
import { TOOL_METADATA } from '../../lib/constants/ai'
import { ERROR_MESSAGES } from '../../lib/constants/messages'
import {
  getAyniteDir,
  getWorkspaceMemoryPath,
  getWorkspaceTaskPath,
  secureEditFile,
  secureGetFileTree,
  secureGlobSearch,
  secureGrepSearch,
  secureListDir,
  secureReadText,
  secureWriteText,
  writeText,
} from '../../lib/path'
import { requestAiApproval } from '../window'
import { getWorkspacesList } from '../workspace/logic'

const execAsync = promisify(exec)

import type { ToolContext } from '../../lib/types/ai'

export type { ToolContext }

export function getToolsMetadata() {
  return Object.entries(TOOL_METADATA).map(([id, meta]) => ({
    id,
    ...meta,
  }))
}

export function createTools(context: ToolContext) {
  const domains = [...context.workspaceFolders, getAyniteDir()]
  const tools: any = {
    read_file: {
      description: TOOL_METADATA.read_file.description,
      inputSchema: jsonSchema(TOOL_METADATA.read_file.inputSchema),
      execute: async ({ path: filePath }: { path: string }) => {
        return await secureReadText(filePath, domains)
      },
    },
    write_file: {
      description: TOOL_METADATA.write_file.description,
      inputSchema: jsonSchema(TOOL_METADATA.write_file.inputSchema),
      execute: async ({
        path: filePath,
        content,
      }: {
        path: string
        content: string
      }) => {
        return await secureWriteText(filePath, content, domains)
      },
    },
    edit_file: {
      description: TOOL_METADATA.edit_file.description,
      inputSchema: jsonSchema(TOOL_METADATA.edit_file.inputSchema),
      execute: async ({
        path: filePath,
        targetContent,
        replacementContent,
      }: {
        path: string
        targetContent: string
        replacementContent: string
      }) => {
        return await secureEditFile(
          filePath,
          targetContent,
          replacementContent,
          domains,
        )
      },
    },
    list_files: {
      description: TOOL_METADATA.list_files.description,
      inputSchema: jsonSchema(TOOL_METADATA.list_files.inputSchema),
      execute: async ({ path: dirPath }: { path: string }) => {
        return await secureListDir(dirPath, domains)
      },
    },
    run_command: {
      description: TOOL_METADATA.run_command.description,
      inputSchema: jsonSchema(TOOL_METADATA.run_command.inputSchema),
      execute: async ({ command, cwd }: { command: string; cwd?: string }) => {
        const runCwd = cwd || context.workspaceFolders[0] || '.'

        const approved = await requestAiApproval({
          command,
          cwd: runCwd,
        })

        if (!approved) return ERROR_MESSAGES.COMMAND_REJECTED

        try {
          const { stdout, stderr } = await execAsync(command, { cwd: runCwd })
          let output = stdout
          if (stderr?.trim()) {
            output += `\n\nSTDERR:\n${stderr}`
          }

          try {
            const parsed = JSON.parse(stdout.trim())
            if (
              parsed &&
              typeof parsed === 'object' &&
              parsed.status === 'error'
            ) {
              throw new Error(output)
            }
          } catch (_jsonErr) {}

          return output
        } catch (e: unknown) {
          const cmdErr = e as {
            stdout?: string
            stderr?: string
            message?: string
          }
          return ERROR_MESSAGES.COMMAND_EXEC_ERROR(
            cmdErr.message || '',
            cmdErr.stdout || '',
            cmdErr.stderr || '',
          )
        }
      },
    },
    grep_search: {
      description: TOOL_METADATA.grep_search.description,
      inputSchema: jsonSchema(TOOL_METADATA.grep_search.inputSchema),
      execute: async ({
        pattern,
        folderPath,
      }: {
        pattern: string
        folderPath: string
      }) => {
        return await secureGrepSearch(folderPath, pattern, domains)
      },
    },
    read_url: {
      description: TOOL_METADATA.read_url.description,
      inputSchema: jsonSchema(TOOL_METADATA.read_url.inputSchema),
      execute: async ({ url }: { url: string }) => {
        try {
          const response = await fetch(url, {
            headers: {
              'User-Agent':
                'Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/120.0.0.0 Safari/537.36',
            },
          })
          if (!response.ok)
            return ERROR_MESSAGES.URL_FETCH_ERROR(response.statusText)
          const text = await response.text()
          return text
            .replace(/<script\b[^>]*>([\s\S]*?)<\/script>/gi, '')
            .replace(/<style\b[^>]*>([\s\S]*?)<\/style>/gi, '')
            .replace(/<[^>]*>/g, ' ')
            .replace(/\s+/g, ' ')
            .trim()
            .slice(0, 10000)
        } catch (e: unknown) {
          const message = e instanceof Error ? e.message : String(e)
          return ERROR_MESSAGES.URL_GENERIC_ERROR(message)
        }
      },
    },
    glob_search: {
      description: TOOL_METADATA.glob_search.description,
      inputSchema: jsonSchema(TOOL_METADATA.glob_search.inputSchema),
      execute: async ({ pattern, cwd }: { pattern: string; cwd?: string }) => {
        return await secureGlobSearch(pattern, domains, cwd)
      },
    },
    create_task: {
      description: TOOL_METADATA.create_task.description,
      inputSchema: jsonSchema(TOOL_METADATA.create_task.inputSchema),
      execute: async ({
        tasks,
        filename,
      }: {
        tasks: string[]
        filename?: string
      }) => {
        const { active } = await getWorkspacesList()
        const taskPath = getWorkspaceTaskPath(active, filename)
        const content = tasks.map((t) => `- [ ] ${t}`).join('\n')
        await writeText(taskPath, content)
        return `Created task list at ${taskPath}`
      },
    },
    update_task: {
      description: TOOL_METADATA.update_task.description,
      inputSchema: jsonSchema(TOOL_METADATA.update_task.inputSchema),
      execute: async ({
        taskIndex,
        status,
        filename,
      }: {
        taskIndex: number
        status: 'todo' | 'in_progress' | 'done'
        filename?: string
      }) => {
        const { active } = await getWorkspacesList()
        const taskPath = getWorkspaceTaskPath(active, filename)
        try {
          const content = await secureReadText(taskPath, domains)
          if (content.startsWith('Error')) return content

          const lines = content.split('\n')
          if (taskIndex < 0 || taskIndex >= lines.length) {
            return `Error: Task index ${taskIndex} out of range (0-${lines.length - 1})`
          }

          const statusMap = {
            todo: '[ ]',
            in_progress: '[/]',
            done: '[x]',
          }

          lines[taskIndex] = lines[taskIndex].replace(
            /\[[ x/]?\]/,
            statusMap[status],
          )
          await writeText(taskPath, lines.join('\n'))
          return `Updated task ${taskIndex} to ${status}`
        } catch (e) {
          return `Error updating task: ${e instanceof Error ? e.message : String(e)}`
        }
      },
    },
    get_tasks: {
      description: TOOL_METADATA.get_tasks.description,
      inputSchema: jsonSchema(TOOL_METADATA.get_tasks.inputSchema),
      execute: async ({ filename }: { filename?: string }) => {
        const { active } = await getWorkspacesList()
        const taskPath = getWorkspaceTaskPath(active, filename)
        return await secureReadText(taskPath, domains)
      },
    },
    propose_plan: {
      description: TOOL_METADATA.propose_plan.description,
      inputSchema: jsonSchema(TOOL_METADATA.propose_plan.inputSchema),
      execute: async ({
        problemStatement,
        investigationResults,
        proposedArchitecture,
        implementationSteps,
        verificationPlan,
        openQuestions,
      }: {
        problemStatement: string
        investigationResults: string
        proposedArchitecture: string
        implementationSteps: string[]
        verificationPlan: string
        openQuestions?: string[]
      }) => {
        const { active } = await getWorkspacesList()
        const planPath = getWorkspaceTaskPath(active, 'implementation_plan.md')

        const content = [
          '# Implementation Plan',
          '',
          '## 1. Problem Statement',
          problemStatement,
          '',
          '## 2. Investigation Results',
          investigationResults,
          '',
          '## 3. Proposed Architecture & Trade-offs',
          proposedArchitecture,
          '',
          '## 4. Implementation Steps',
          implementationSteps.map((s, i) => `${i + 1}. ${s}`).join('\n'),
          '',
          '## 5. Verification Plan',
          verificationPlan,
          '',
          '## 6. Open Questions & Assumptions',
          openQuestions?.length
            ? openQuestions.map((q) => `- ${q}`).join('\n')
            : 'None',
        ].join('\n')

        await writeText(planPath, content)
        return `Implementation plan proposed at ${planPath}. Please review the file and type "Approved" to proceed.`
      },
    },
    initialize_memory: {
      description: TOOL_METADATA.initialize_memory.description,
      inputSchema: jsonSchema(TOOL_METADATA.initialize_memory.inputSchema),
      execute: async () => {
        const { active } = await getWorkspacesList()
        const memoryPath = getWorkspaceMemoryPath(active)

        // Gather intelligence
        const pkgPath = domains[0] ? `${domains[0]}/package.json` : null
        const readmePath = domains[0] ? `${domains[0]}/README.md` : null

        let pkgInfo = 'Unknown'
        if (pkgPath) {
          const content = await secureReadText(pkgPath, domains)
          if (!content.startsWith('Error')) {
            try {
              const pkg = JSON.parse(content)
              pkgInfo = `Project: ${pkg.name}\nVersion: ${pkg.version}\nDependencies: ${Object.keys(
                pkg.dependencies || {},
              ).join(', ')}`
            } catch (_e) {
              pkgInfo = 'Invalid package.json'
            }
          }
        }

        let readmeInfo = ''
        if (readmePath) {
          const content = await secureReadText(readmePath, domains)
          if (!content.startsWith('Error')) {
            readmeInfo = content.slice(0, 1000) // First 1000 chars
          }
        }

        const tree = await secureGetFileTree(domains[0], domains, 2)

        const content = [
          '# Project Memory',
          '',
          '## 🎯 Overview',
          readmeInfo || 'No summary available yet.',
          '',
          '## 📂 Structure',
          `\`\`\`\n${tree}\n\`\`\``,
          '',
          '## 📜 Rules & Conventions',
          pkgInfo !== 'Unknown' ? `- Tech Stack: ${pkgInfo}` : '',
          '- (Record styles, patterns, or project rules here)',
          '',
          '## 💡 Key Decisions & Context',
          '- (Record important architectural or narrative decisions here)',
        ]
          .filter(Boolean)
          .join('\n')

        await writeText(memoryPath, content)
        return `Project memory initialized at ${memoryPath}. You should now update it with specific project secrets or conventions.`
      },
    },
    update_memory: {
      description: TOOL_METADATA.update_memory.description,
      inputSchema: jsonSchema(TOOL_METADATA.update_memory.inputSchema),
      execute: async ({ update }: { update: string }) => {
        const { active } = await getWorkspacesList()
        const memoryPath = getWorkspaceMemoryPath(active)
        try {
          const current = await secureReadText(memoryPath, domains)
          const content = current.startsWith('Error')
            ? `# Project Memory\n\n${update}`
            : `${current}\n\n### Update (${new Date().toLocaleDateString()})\n${update}`

          await writeText(memoryPath, content)
          return `Project memory updated at ${memoryPath}`
        } catch (e) {
          return `Error updating memory: ${e instanceof Error ? e.message : String(e)}`
        }
      },
    },
    read_memory: {
      description: TOOL_METADATA.read_memory.description,
      inputSchema: jsonSchema(TOOL_METADATA.read_memory.inputSchema),
      execute: async () => {
        const { active } = await getWorkspacesList()
        const memoryPath = getWorkspaceMemoryPath(active)
        const content = await secureReadText(memoryPath, domains)
        if (content.startsWith('Error')) {
          return 'No project memory found. You can initialize it using "initialize_memory".'
        }
        return content
      },
    },
    get_file_tree: {
      description: TOOL_METADATA.get_file_tree.description,
      inputSchema: jsonSchema(TOOL_METADATA.get_file_tree.inputSchema),
      execute: async ({
        path: dirPath,
        depth = 10,
      }: {
        path?: string
        depth?: number
      }) => {
        if (dirPath) {
          return await secureGetFileTree(dirPath, domains, depth)
        } else {
          let fullOutput = ''
          for (const folder of context.workspaceFolders) {
            fullOutput += `Workspace Folder: ${folder}\n`
            fullOutput += await secureGetFileTree(folder, domains, depth)
            fullOutput += '\n'
          }
          return fullOutput || ERROR_MESSAGES.WORKSPACE_EMPTY
        }
      },
    },
    get_workspace_info: {
      description: TOOL_METADATA.get_workspace_info.description,
      inputSchema: jsonSchema(TOOL_METADATA.get_workspace_info.inputSchema),
      execute: async () => {
        return {
          workspaceFolders: context.workspaceFolders,
          configDir: getAyniteDir(),
          activeFile: context.activeFile || null,
        }
      },
    },
  }

  return tools
}

import {
  app,
  BrowserWindow,
  clipboard,
  ipcMain,
  net,
  protocol,
  shell,
} from 'electron'
import {
  exists,
  expandHome,
  copy as fsCopy,
  getBasename,
  joinPaths,
} from '../../lib/path'
import {
  createNewWindow,
  sendAppEvent,
  showOpenDialog,
  showSaveDialog,
} from '../window'
import { getAvailableViews, getSystemFonts } from './logic'

let clipboardPath: string | null = null

// ─── Channel constants ────────────────────────────────────────────────────
import { AppEvents } from '../../lib/constants/app'
import { SystemChannels } from '../../lib/constants/ipc-channels'

export function setupSystemIpc() {
  ipcMain.handle(SystemChannels.FONT_LIST, async () => {
    return await getSystemFonts()
  })

  ipcMain.handle(SystemChannels.OPEN_EXTERNAL, async (_event, url: string) => {
    await shell.openExternal(url)
    return true
  })

  ipcMain.handle(SystemChannels.APP_VERSION, () => {
    return app.getVersion()
  })

  ipcMain.handle(SystemChannels.APP_QUIT, () => {
    app.quit()
  })

  ipcMain.handle(SystemChannels.DIALOG_SELECT_FILE, async () => {
    const { canceled, filePaths } = await showOpenDialog({
      properties: ['openFile'],
    })
    if (canceled || filePaths.length === 0) return null
    return filePaths[0]
  })

  ipcMain.handle(SystemChannels.DIALOG_SELECT_FOLDER, async () => {
    const { canceled, filePaths } = await showOpenDialog({
      properties: ['openDirectory'],
    })
    if (canceled || filePaths.length === 0) return null
    return filePaths
  })

  ipcMain.handle(SystemChannels.DIALOG_SAVE_FILE, async () => {
    const { canceled, filePath } = await showSaveDialog({
      filters: [{ name: 'JSON', extensions: ['json'] }],
    })
    if (canceled || !filePath) return null
    return filePath
  })

  ipcMain.handle(SystemChannels.WINDOW_MINIMIZE, (event) => {
    BrowserWindow.fromWebContents(event.sender)?.minimize()
    return true
  })

  ipcMain.handle(SystemChannels.WINDOW_MAXIMIZE, (event) => {
    const win = BrowserWindow.fromWebContents(event.sender)
    if (win) {
      if (win.isMaximized()) {
        win.unmaximize()
      } else {
        win.maximize()
      }
    }
    return true
  })

  ipcMain.handle(SystemChannels.WINDOW_CLOSE, (event) => {
    const win = BrowserWindow.fromWebContents(event.sender)
    if (win && !win.isDestroyed()) {
      win.close()
    }
    return true
  })

  ipcMain.handle(SystemChannels.WINDOW_NEW, () => {
    createNewWindow()
    return true
  })

  ipcMain.handle(
    SystemChannels.CLIPBOARD_COPY,
    async (_event, path: string) => {
      clipboardPath = path
      return true
    },
  )

  ipcMain.handle(
    SystemChannels.CLIPBOARD_PASTE,
    async (_event, destDir: string) => {
      if (!clipboardPath) return false
      const fileName = getBasename(clipboardPath)
      const destPath = joinPaths(destDir, fileName)
      if (await exists(clipboardPath)) {
        await fsCopy(clipboardPath, destPath, { recursive: true })
        return true
      }
      return false
    },
  )

  ipcMain.handle(SystemChannels.VIEW_LIST, async () => {
    return await getAvailableViews()
  })

  ipcMain.handle(
    SystemChannels.TILE_ACTIVATE,
    async (_event, tileId: string) => {
      sendAppEvent(AppEvents.TILE_ACTIVATED, tileId)
      return true
    },
  )

  ipcMain.handle(
    SystemChannels.CLIPBOARD_WRITE_TEXT,
    (_event, text: string) => {
      clipboard.writeText(text)
      return true
    },
  )
}

export function setupProtocol() {
  // aynite:// protocol for internal views
  protocol.handle('aynite', async (request) => {
    const url = request.url.replace('aynite://', '')
    try {
      const decodedPath = decodeURIComponent(url)
      let filePath = ''

      if (decodedPath.includes('assets/')) {
        // Redirect asset requests to ~/.aynite/assets
        const assetPath = decodedPath.split('assets/').pop()
        if (assetPath) {
          filePath = expandHome(joinPaths('~/.aynite', 'assets', assetPath))
        }
      } else {
        filePath = expandHome(joinPaths('~/.aynite', 'views', decodedPath))
      }

      const fileUrl = `file://${filePath.startsWith('/') ? '' : '/'}${filePath}`
      return net.fetch(fileUrl)
    } catch (e) {
      console.error('Failed to handle aynite protocol:', e)
      return new Response('View not found', { status: 404 })
    }
  })

  // aynite-resource:// protocol for arbitrary files
  protocol.handle('aynite-resource', (request) => {
    const url = request.url.replace('aynite-resource://', '')
    try {
      const decodedPath = decodeURIComponent(url)
      const fileUrl = `file://${decodedPath.startsWith('/') ? '' : '/'}${decodedPath}`
      return net.fetch(fileUrl)
    } catch (e) {
      console.error('Failed to handle resource request:', e)
      return new Response('File not found', { status: 404 })
    }
  })
}

export { getAvailableViews, getSystemFonts } from './logic'

import { app, BrowserWindow, protocol } from 'electron'

// IPC & Logic Modules
import { setupAiIpc } from './ai/index'
import { initAppFolders, setupConfigIpc } from './config/index'
import { setupFileIpc, setupWatcher } from './file/index'
import { setupGitIpc } from './git/index'
import { setupKeybindings } from './keybindings'
import { setupRssIpc } from './rss/index'
import { setupSpellsIpc } from './spells/index'
import { setupSpotifyIpc } from './spotify/index'
import { handleSpotifyAuthCode } from './spotify/logic'
import { setupProtocol, setupSystemIpc } from './system/index'
import { setupThemeIpc } from './theme/index'
import { setupUpdater } from './updater'
import { createMainWindow, isWindowActive } from './window'
import { setupWorkspaceIpc } from './workspace/index'

/**
 * App Lifecycle & Initialization
 */

// Linux Specific Optimizations
if (process.platform === 'linux') {
  app.commandLine.appendSwitch('enable-wayland-ime')
  app.commandLine.appendSwitch('wayland-text-input-v3')
}

// Register Custom Protocols
protocol.registerSchemesAsPrivileged([
  {
    scheme: 'aynite',
    privileges: {
      standard: true,
      secure: true,
      supportFetchAPI: true,
      corsEnabled: true,
    },
  },
])

/**
 * OS-level protocol registration for aynite://
 * Handles incoming URLs (e.g. aynite://auth/spotify/callback?code=xxx)
 */

// Route incoming aynite:// protocol URLs to the appropriate module
function handleProtocolUrl(urlStr: string) {
  try {
    const url = new URL(urlStr)
    // aynite://auth/spotify/callback?code=xxx
    // parses as hostname=auth, pathname=/spotify/callback
    const route = url.hostname + url.pathname

    if (route === 'auth/spotify/callback') {
      const code = url.searchParams.get('code')
      if (code) handleSpotifyAuthCode(code)
      return
    }
    // Future: route other aynite:// URLs here
  } catch (err) {
    console.error('[Protocol] Failed to handle URL:', urlStr, err)
  }
}

// Single instance lock — required for second-instance protocol events on Linux/Windows
const gotLock = app.requestSingleInstanceLock()
if (!gotLock) {
  app.quit()
} else {
  app.on('second-instance', (_event, argv) => {
    // Focus the existing window
    for (const win of BrowserWindow.getAllWindows()) {
      if (!win.isMinimized()) win.focus()
    }
    // Check for aynite:// protocol URL in the second instance's args
    const url = argv.find((arg) => arg.startsWith('aynite://'))
    if (url) handleProtocolUrl(url)
  })
}

// Register aynite:// as an OS-level protocol handler
// On Linux this creates a .desktop entry; returns false if unavailable (e.g. dev)
const protocolAvailable = app.setAsDefaultProtocolClient('aynite')

// macOS: handle open-url events
app.on('open-url', (event, url) => {
  event.preventDefault()
  handleProtocolUrl(url)
})

app.whenReady().then(async () => {
  // 1. Essential System Setup
  setupProtocol()
  await initAppFolders()

  // 2. Window Initialization (Centralized in window.ts)
  createMainWindow(__dirname)

  if (isWindowActive()) {
    // 3. Core IPC & Configuration
    setupConfigIpc()
    setupThemeIpc()
    setupKeybindings()

    setupSystemIpc()
    setupUpdater()

    // 4. Workspace & File Management
    setupWorkspaceIpc()
    setupFileIpc()

    // Initial watcher setup
    setupWatcher()

    // 5. Feature Subsystems (AI, Spells, Git)
    setupAiIpc()
    setupSpellsIpc()
    setupRssIpc()
    setupSpotifyIpc(protocolAvailable)
    setupGitIpc()
  }

  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      createMainWindow(__dirname)
    }
  })
})

